import { redirect } from '@sveltejs/kit';
import type { Cookies, RequestEvent } from '@sveltejs/kit';

// $types is generated by svelte-kit sync; fall back to RequestEvent when not yet generated
type LoadEvent = { cookies: Cookies; fetch: RequestEvent['fetch']; url: URL };

// Server-side env vars — VITE_* not available here, but fall back for local dev parity
const MOCK = process.env.MOCK_FINANCE === 'true' || process.env.VITE_MOCK_FINANCE === 'true';
const baseUrl =
  process.env.GATEWAY_URL ?? process.env.VITE_GATEWAY_URL ?? 'http://localhost:4000';

// ---- Types ----

export interface AccountSummary {
  account_code: string;
  debit_total: number;
  credit_total: number;
  net: number; // debit - credit
}

export interface JournalLine {
  id: string;
  entry_id: string;
  account_code: string;
  debit: number;
  credit: number;
}

export interface JournalEntry {
  id: string;
  idempotency_key: string;
  source_type: string;
  source_id: string;
  posted_at: string; // ISO 8601 RFC3339
  description: string;
  lines: JournalLine[];
}

export interface PageData {
  summary: AccountSummary[];
  journals: JournalEntry[];
  next_cursor: string | null;
  error: string | null;
}

