// ---- Load function ----

export const load = async ({ cookies, fetch, url }: LoadEvent): Promise<PageData> => {
  const accessToken = cookies.get('umrohos_access_token');
  if (!accessToken) {
    throw redirect(303, '/console/login');
  }

  if (MOCK) {
    return {
      summary: MOCK_SUMMARY,
      journals: MOCK_JOURNALS,
      next_cursor: null,
      error: null
    };
  }

  // Read optional filter/pagination query params from the current URL
  const from = url.searchParams.get('from') ?? '';
  const to = url.searchParams.get('to') ?? '';
  const cursor = url.searchParams.get('cursor') ?? '';
  const limitParam = url.searchParams.get('limit') ?? '50';

  // Build journals query string
  const journalParams = new URLSearchParams();
  journalParams.set('limit', limitParam);
  if (from) journalParams.set('from', from);
  if (to) journalParams.set('to', to);
  if (cursor) journalParams.set('cursor', cursor);

  try {
    const [summaryRes, journalsRes] = await Promise.all([
      fetch(`${baseUrl}/v1/finance/summary`, {
        headers: { Authorization: `Bearer ${accessToken}` }
      }),
      fetch(`${baseUrl}/v1/finance/journals?${journalParams.toString()}`, {
        headers: { Authorization: `Bearer ${accessToken}` }
      })
    ]);

    // Gateway returns { data: AccountBalanceData[] } for summary
    const summaryBody: { data: AccountSummary[] } = summaryRes.ok
      ? ((await summaryRes.json()) as { data: AccountSummary[] })
      : { data: [] };

    // Gateway returns { data: JournalEntryData[], next_cursor: string } for journals
    const journalsBody: { data: JournalEntry[]; next_cursor: string | null } = journalsRes.ok
      ? ((await journalsRes.json()) as { data: JournalEntry[]; next_cursor: string | null })
      : { data: [], next_cursor: null };

    const error =
      !summaryRes.ok
        ? `Gagal memuat ringkasan akun (${summaryRes.status})`
        : !journalsRes.ok
          ? `Gagal memuat riwayat jurnal (${journalsRes.status})`
          : null;

    return {
      summary: Array.isArray(summaryBody.data) ? summaryBody.data : [],
      journals: journalsBody.data ?? [],
      next_cursor: journalsBody.next_cursor ?? null,
      error
    };
  } catch {
    return {
      summary: [],
      journals: [],
      next_cursor: null,
      error: 'Tidak dapat terhubung ke gateway.'
    };
  }
};
